const body = $json.body || {};

const channel = body.channel || 'whatsapp';
const channelUserId = body.from || null;

return [
  {
    json: {
      channel,
      channelUserId,
      sessionId: `${channel}:${channelUserId}`,
      messageText: body.text || '',
      attachments: Array.isArray(body.attachments) ? body.attachments : [],
      hasAttachment: Array.isArray(body.attachments) && body.attachments.length > 0,
      receivedAt: new Date().toISOString()
    }
  }
];

const normalized = $('Normalize Input').first().json;
const dbRow = $json;

let context;
let isNew = false;

if (!dbRow || !dbRow.session_id) {
  isNew = true;
  context = {
    session_id: normalized.sessionId,
    channel: normalized.channel,
    channel_user_id: normalized.channelUserId,
    stage: 'discovery',
    lead: {},
    energy: {},
    installation: {},
    location: {},
    backend: {},
    conversation: { missing_fields: [] }
  };
} else {
  context = dbRow.context_json || {};
}

return [{
  json: {
    ...normalized,
    sessionId: normalized.sessionId,
    context,
    isNewSession: isNew
  }
}];

// Parse bill extraction result from LLM
const rawText = $json.text || $json.output || '';

let parsed;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch (e) {
  parsed = {
    monthly_consumption_kwh: null,
    bill_amount_brl: null,
    utility_company: null,
    connection_type: null,
    extraction_notes: 'Não foi possível ler o documento'
  };
}

// Get the session data from Resolve Session
const base = $('Resolve Session').first().json;
const context = JSON.parse(JSON.stringify(base.context || {}));

context.energy = context.energy || {};

// Merge extracted bill data into context
if (parsed.monthly_consumption_kwh) context.energy.monthly_consumption_kwh = parsed.monthly_consumption_kwh;
if (parsed.bill_amount_brl)         context.energy.bill_amount_brl         = parsed.bill_amount_brl;
if (parsed.utility_company)         context.energy.utility_company         = parsed.utility_company;
if (parsed.connection_type)         context.energy.connection_type         = parsed.connection_type;

context.energy.bill_document_received = true;

// Build a reply based on what was extracted
const got = [];
if (parsed.monthly_consumption_kwh) got.push(`consumo de *${parsed.monthly_consumption_kwh} kWh*`);
if (parsed.bill_amount_brl)         got.push(`valor de *R$ ${Number(parsed.bill_amount_brl).toFixed(2).replace('.', ',')}*`);
if (parsed.utility_company)         got.push(`distribuidora *${parsed.utility_company}*`);

let reply;
if (got.length > 0) {
  reply = `Recebi sua conta! Identifiquei ${got.join(', ')}. `;
} else {
  reply = `Recebi o documento, mas não consegui ler os dados automaticamente. Pode me informar seu consumo mensal em kWh e o valor da conta? `;
}

context.conversation = context.conversation || {};
context.conversation.last_bot_message = reply;

return [{
  json: {
    ...base,
    context,
    outboundText: reply,
    billExtracted: true
  }
}];

// Parse LLM output
const rawText = $json.text || $json.output || '';

let parsed;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch (e) {
  parsed = {
    entities_to_save: {},
    draft_reply: 'Desculpe, não entendi muito bem. Pode repetir?'
  };
}

// Get session data — could come from bill extraction branch OR directly from Resolve Session
let base;
try {
  base = $('Parse Bill Extraction').first().json;
} catch(e) {
  base = $('Resolve Session').first().json;
}

const context = JSON.parse(JSON.stringify(base.context || {}));

context.lead         = context.lead         || {};
context.energy       = context.energy       || {};
context.installation = context.installation || {};
context.location     = context.location     || {};
context.conversation = context.conversation || {};

// Merge extracted entities (only non-empty values, never overwrite with empty)
const entities = parsed.entities_to_save || {};
if (entities.lead) {
  Object.entries(entities.lead).forEach(([k, v]) => { if (v !== null && v !== undefined && v !== '') context.lead[k] = v; });
}
if (entities.energy) {
  Object.entries(entities.energy).forEach(([k, v]) => { if (v !== null && v !== undefined && v !== '') context.energy[k] = v; });
}
if (entities.installation) {
  Object.entries(entities.installation).forEach(([k, v]) => { if (v !== null && v !== undefined && v !== '') context.installation[k] = v; });
}

// -------------------------------------------------------
// DETERMINISTIC missing_fields — code decides, not LLM
// -------------------------------------------------------
const missing = [];

if (!context.lead.full_name) missing.push('full_name');

const hasConsumption  = !!context.energy.monthly_consumption_kwh;
const billNotAvail    = !!context.energy.bill_not_available;
const billDocReceived = !!context.energy.bill_document_received;

if (!hasConsumption) {
  missing.push(billNotAvail || billDocReceived ? 'monthly_consumption_kwh' : 'bill_document_or_energy_data');
}

if (!context.installation.installation_type) missing.push('installation_type');
if (!context.installation.roof_type)         missing.push('roof_type');

const hasLocation = context.lead.address_text || (context.lead.city && context.lead.state);
if (!hasLocation) missing.push('location');

// -------------------------------------------------------
// DETERMINISTIC is_ready_for_quote
// Minimum: name + kWh + installation type + roof type
// -------------------------------------------------------
const isReadyForQuote = !!(
  context.lead.full_name &&
  context.energy.monthly_consumption_kwh &&
  context.installation.installation_type &&
  context.installation.roof_type
);

context.conversation.missing_fields    = missing;
context.conversation.last_user_message = base.messageText;
context.conversation.last_bot_message  = parsed.draft_reply;

return [{
  json: {
    ...base,
    context,
    outboundText: parsed.draft_reply,
    isReadyForQuote,
    llmOutput: parsed
  }
}];

const ctx = $json.context || {};
const lead = ctx.lead || {};
const energy = ctx.energy || {};
const installation = ctx.installation || {};

return [{
  json: {
    ...$json,
    apiPayload: {
      lead: {
        full_name:    lead.full_name    || null,
        phone:        $json.channelUserId || null,
        city:         lead.city         || null,
        state:        lead.state        || null,
        address_text: lead.address_text || null,
        source: 'whatsapp'
      },
      budget_request: {
        monthly_consumption_kwh: energy.monthly_consumption_kwh || null,
        bill_amount_brl:         energy.bill_amount_brl         || null,
        utility_company:         energy.utility_company         || null,
        connection_type:         energy.connection_type         || null,
        installation_type:       installation.installation_type || null,
        roof_type:               installation.roof_type         || null
      }
    }
  }
}];

const apiResponse = $json;
const quote = apiResponse.quote_version || {};
const kit   = apiResponse.selected_kit  || null;

const base = $('Parse LLM Response').first().json;
const context = JSON.parse(JSON.stringify(base.context || {}));

context.backend = context.backend || {};
context.backend.quote_generated = true;
context.backend.quote_id        = quote.id || null;
context.backend.quote_kwp       = quote.estimated_system_kwp || null;
context.backend.quote_price     = quote.estimated_price_brl  || null;
if (kit) context.backend.selected_kit_id = kit.id;

// Format numbers for PT-BR display
const fmtBRL = (v) => Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const kwp    = Number(quote.estimated_system_kwp || 0).toFixed(2);

let reply = `Perfeito, ${context.lead.full_name || 'cliente'}! Preparei sua estimativa:\n\n`;
reply += `⚡ *Sistema necessário:* ${kwp} kWp\n`;

if (kit) {
  const modules = kit.module_quantity ? `${kit.module_quantity} painéis de ${kit.module_power_w}W` : '';
  reply += `\n📦 *Kit recomendado:*\n`;
  reply += `${kit.supplier_kit_name}\n`;
  if (modules) reply += `${modules} · Inversor ${kit.inverter_power_kw} kW\n`;
  reply += `Marca módulo: ${kit.brand_module || '—'} · Inversor: ${kit.brand_inverter || '—'}\n`;
  if (kit.price_cash_brl) {
    reply += `💰 *${fmtBRL(kit.price_cash_brl)}* à vista`;
    if (kit.price_term_brl) reply += ` | ${fmtBRL(kit.price_term_brl)} a prazo`;
    reply += `\n`;
  }
  if (kit.availability_text) reply += `Disponibilidade: ${kit.availability_text}\n`;
} else {
  reply += `\n⚠️ Nenhum kit disponível no momento para esse perfil. Entraremos em contato em breve.\n`;
}

if (quote.estimated_savings_brl) {
  reply += `\n💡 *Economia mensal estimada:* ${fmtBRL(quote.estimated_savings_brl)}\n`;
}

reply += `\nEssa é uma estimativa preliminar. Posso passar você para um de nossos consultores para detalhar a proposta. Tem interesse?`;

context.conversation.last_bot_message = reply;

return [{
  json: {
    ...base,
    context,
    outboundText: reply
  }
}];

parameters.query:
insert into conversation.conversation_sessions (
  session_id, channel, channel_user_id, context_json, created_at, updated_at
)
values ($1, $2, $3, $4::jsonb, now(), now())
returning *;

parameters.jsCode:
return [{
  json: {
    session_id: $json.sessionId,
    direction: 'inbound',
    message_text: $json.messageText || '',
    payload_json: {
      channel: $json.channel,
      channelUserId: $json.channelUserId,
      messageText: $json.messageText,
      attachments: $json.attachments || [],
      receivedAt: $json.receivedAt
    }
  }
}];

parameters.query:
update conversation.conversation_sessions
set context_json = $2::jsonb, updated_at = now()
where session_id = $1;

